// ProviderConfig holds connection details for an LLM provider.
type ProviderConfig struct {
	Kind    string `json:"kind"`     // "openai", "anthropic", "openai-compatible"
	BaseURL string `json:"base_url"` // custom API endpoint (e.g. LiteLLM)
	APIKey  string `json:"api_key"`  // API key or auth token
}

// ResolveProviderOpts builds ProviderOptions for a given provider name,
// merging config file settings with environment variables.
// Env vars take precedence over config values.
func ResolveProviderOpts(name string, cfg *config.Config) llm.ProviderOptions {
	pcfg := cfg.GetProvider(name)
	opts := llm.ProviderOptions{
		APIKey:  pcfg.APIKey,
		BaseURL: pcfg.BaseURL,
		Kind:    pcfg.Kind,
	}

	envPrefix := strings.ToUpper(name)
	if v := os.Getenv(envPrefix + "_API_KEY"); v != "" {
		opts.APIKey = v
	}
	if v := os.Getenv(envPrefix + "_AUTH_TOKEN"); v != "" {
		opts.APIKey = v
	}
	if v := os.Getenv(envPrefix + "_BASE_URL"); v != "" {
		opts.BaseURL = v
	}

	return opts
}

// LLMProvider is the interface for all LLM backends.
type LLMProvider interface {
	ChatStream(ctx context.Context, req ChatRequest) (<-chan ChatEvent, error)
	Models() []ModelInfo
}

// ProviderOptions holds connection details for creating an LLM provider.
type ProviderOptions struct {
	APIKey  string
	BaseURL string
	Kind    string // override: "openai-compatible" uses OpenAI client with custom URL
}

// NewProvider creates an LLMProvider for the given provider name.
func NewProvider(providerName string, opts ProviderOptions) (LLMProvider, error) {
	// If Kind is set, use it to override the provider type.
	// This lets e.g. "anthropic" route through an OpenAI-compatible proxy like LiteLLM.
	kind := opts.Kind
	if kind == "" {
		// If a custom base URL is set, default to openai-compatible
		// since most proxies (LiteLLM, etc.) expose an OpenAI-compatible API.
		if opts.BaseURL != "" {
			kind = "openai-compatible"
		} else {
			kind = providerName
		}
	}

	switch kind {
	case "anthropic":
		return NewAnthropicProvider(opts.APIKey, opts.BaseURL), nil
	case "openai", "openai-compatible":
		return NewOpenAIProvider(opts.APIKey, opts.BaseURL), nil
	default:
		return nil, fmt.Errorf("unknown LLM provider kind: %q", kind)
	}
}

// AnthropicProvider implements LLMProvider using the Anthropic Messages API.
type AnthropicProvider struct {
	client anthropic.Client
}

// NewAnthropicProvider creates a new Anthropic LLM provider.
// If baseURL is non-empty, the client points to that endpoint.
func NewAnthropicProvider(apiKey, baseURL string) *AnthropicProvider {
	opts := []option.RequestOption{option.WithAPIKey(apiKey)}
	if baseURL != "" {
		opts = append(opts, option.WithBaseURL(baseURL))
	}
	client := anthropic.NewClient(opts...)
	return &AnthropicProvider{client: client}
}

